function putOrIncrement(map,key,num) {
  if(map.has(key)){
    let value=map.get(key);
    map.set(key,value+num);
  }else{
    map.set(key, num);
  }

}

const result=[];
const excessSku=[];
//统计该订单已经发货的数量
const shippedWtypeMap=new Map();
for(const item of $input.all()){
  putOrIncrement(shippedWtypeMap,item.json.sku_code,1);
}

//统计该订单将要发货的数量
const shipWtypeMap=new Map();
$('给出库的sn绑定价格').all()[0].json.watch_info.forEach(el=>{
    putOrIncrement(shipWtypeMap,el.sku_code,1);
  })

